const audit = $input.first().json;
const data = $('Analizar factura JSON').first().json;

const factura = data.factura || {};

return [{
  json: {
    status: "PENDING_REVIEW",
    siniestro_id: factura.siniestro_id || "N/A",
    taller: factura.taller || "N/A",
    numero_factura: factura.numero || "N/A",
    approvedAmount: audit.approvedAmount || 0,
    totalDiscrepancies: audit.totalDiscrepancies || 0,
    discrepancyAmount: audit.discrepancyAmount || 0,
    requiresHumanReview: true,
    recommendations: audit.recommendations || "",
    findings: audit.findings || [],
    duplicateCharges: audit.duplicateCharges || [],
    auditedBy: "AI Agent",
    auditedAt: new Date().toISOString()
  }
}];

const audit = $input.first().json;
const data = $('Analizar factura JSON').first().json;

const factura = data.factura || {};

return [{
  json: {
    status: "APPROVED",
    siniestro_id: factura.siniestro_id || "N/A",
