    requiresHumanReview: false,
    recommendations: audit.recommendations || "Invoice approved",
    findings: [],
    duplicateCharges: [],
    auditedBy: "AI Agent",
    auditedAt: new Date().toISOString()
  }
}];

const raw = $input.first().json.output;
let parsed;

try {
  if (typeof raw === "object") {
    parsed = raw;
  } else {
    const cleaned = raw
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();
    parsed = JSON.parse(cleaned);
  }
} catch (e) {
  parsed = {};
}

const estimacion = $("Analizar factura JSON").first().json.estimacion;
const factura = $("Analizar factura JSON").first().json.factura;

const totalEstimado = estimacion?.total_estimado || 0;
const totalFactura = factura?.total_factura || 0;

return { parsed, totalEstimado, totalFactura };

const input = $input.first().json;

const raw = input.parsed || input.output;
let parsed = {};

try {
  if (typeof raw === 'object' && raw !== null) {
    parsed = raw;
  } else if (typeof raw === 'string') {
    const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
    parsed = JSON.parse(cleaned);
  }
} catch(e) {
  parsed = {};
}

const findings = Array.isArray(parsed.findings) ? parsed.findings : [];
const duplicateCharges = Array.isArray(parsed.duplicateCharges) ? parsed.duplicateCharges : [];
const totalDiscrepancies = typeof parsed.totalDiscrepancies === 'number' ? parsed.totalDiscrepancies : findings.length;
const discrepancyAmount = typeof parsed.discrepancyAmount === 'number' ? parsed.discrepancyAmount : 0;
const approvedAmount = typeof parsed.approvedAmount === 'number' ? parsed.approvedAmount : input.totalEstimado || 0;
const recommendations = Array.isArray(parsed.recommendations) ? parsed.recommendations : typeof parsed.recommendations === 'string' ? [parsed.recommendations] : [];
const hasHighFindings = findings.some(f => f.severity === 'high');
const hasDuplicates = duplicateCharges.length > 0;
const requiresHumanReview = hasHighFindings || hasDuplicates || parsed.requiresHumanReview === true;
const auditStatus = (hasHighFindings || hasDuplicates) ? 'rejected' : (parsed.auditStatus || 'approved');

if (requiresHumanReview && findings.length === 0) {
  findings.push({
    codigo: 'REVIEW_REQUIRED',
    issue: 'Se requiere revisión humana según criterio del agente',
    severity: 'medium',
  });
}

return [{
  json: {
    auditStatus,
    totalDiscrepancies,
    discrepancyAmount,
    approvedAmount,
    requiresHumanReview,
    recommendations,
    findings,
    duplicateCharges,
    siniestro_id: $('Parse Invoice JSON').first().json.factura?.siniestro_id || '',
    taller: $('Parse Invoice JSON').first().json.factura?.taller || '',
    numero_factura: $('Parse Invoice JSON').first().json.factura?.numero || '',
    auditedBy: 'AI Agent',
    auditedAt: new Date().toISOString()
  }
}];
